class Solution {
    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int busIndex = 0;
        int passengerIndex = 0;
        int latestTime = 0;
        while (passengerIndex < passengers.length) {
            if (buses[busIndex] <= passengers[passengerIndex]) {
                int count = 0;
                while (count < capacity && passengerIndex < passengers.length) {
                    buses[busIndex] = passengers[passengerIndex];
                    passengerIndex++;
                    count++;
                }
                busIndex++;
            }
            latestTime = Math.max(latestTime, passengers[passengerIndex]);
        }
        return latestTime;
    }
}
```
